INSERT OR REPLACE INTO law_article (law_key, mst, article_no, title, body, source_url, updated_at)
VALUES ('004946','273373','제4조','경형자동차 및 환경친화적 자동차 전용주차구획의 설치비율','제4조(경형자동차 및 환경친화적 자동차 전용주차구획의 설치비율) 법 제12조의3제1항에 따른 단지조성사업등(이하 "단지조성사업등"이라 한다)으로 설치되는 노외주차장에는 같은 조 제3항에 따라 경형자동차 및 환경친화적 자동차를 위한 전용주차구획을 다음 각 호의 비율이 모두 충족되도록 설치해야 한다.','http://www.law.go.kr/DRF/lawService.do?OC=dudy3038&target=eflaw&type=JSON&MST=273373', datetime('now'));
